sql:
SELECT COUNT(*) AS writable_sensor_points_count
FROM sensor_points
WHERE writable = 1;

SELECT point_name
FROM sensor_points
WHERE point_id = 1;

SELECT status, COUNT(*) AS sensor_count
FROM sensor_points
GROUP BY status;

